@startuml
skinparam packageStyle rectangle

package "surcharge" {
    frame seat {
        class SeatType <<E>> {
            FreeSeat
            ReservedSeat
            --
            + abstract createSeat(superExpress : SuperExpress) : Seat
        }

        interface I_Seat as Seat {
            getSeatSurcharge()
        }

        note right of Seat: Interface for seats\nwith surcharges

        class C_FreeSeat as FreeSeat {
            Hikari
            - 
            + getSeatSurcharge(): Yen
        }

        class C_ReservedSeat as ReservedSeat {
            SuperExpress
            - 
            + getSeatSurcharge(): Yen
        }

        ' Relationships in seat section
        Seat <|-- FreeSeat
        Seat <|-- ReservedSeat
        SeatType o-- Seat
    }

    frame superexpress {
        enum ShinkansenType <<enumeration>> {
            Hikari
            Nozomi

            static method::createSuperExpress(destination): SuperExpress
        }

